import {
  type ImageProps,
  type Loader,
  loaderProp,
  RawLoaderPropsParser,
  SqsLoaderPropsParser,
  VimeoLoaderPropsParser,
  YoutubeLoaderPropsParser,
} from '../schema.js';

type PropsParser =
  | typeof SqsLoaderPropsParser
  | typeof VimeoLoaderPropsParser
  | typeof RawLoaderPropsParser
  | typeof YoutubeLoaderPropsParser;
const getParser = (loader: Loader): PropsParser => {
  switch (loader) {
    case 'sqs':
      return SqsLoaderPropsParser;
    case 'vimeo':
      return VimeoLoaderPropsParser;
    case 'youtube':
      return YoutubeLoaderPropsParser;
    case 'raw':
    default:
      return RawLoaderPropsParser;
  }
};

const errorFormatter = (prop: string, message: string): string =>
  `ERROR(@sqs/image): prop '${prop}' - ${message}`;

export function validate<L extends Loader>(props: ImageProps<L>): string[] {
  const result = loaderProp.safeParse(props.loader);
  if (!result.success) {
    return result.error.issues.map((issue) => errorFormatter('loader', issue.message));
  }

  const fullSchema = getParser(result.data);
  const fullResult = fullSchema.safeParse(props);
  if (!fullResult.success) {
    return fullResult.error.issues.map((issue) =>
      errorFormatter(issue.path.join('.'), issue.message)
    );
  }
  return [];
}

export function log(messages: string[]): void {
  console.group('@sqs/image logs');
  for (const message of messages) {
    console.error(message);
  }
  console.groupEnd();
}
